import{_ as a,r as s,o,c,a as n,b as l,w as d,e as t,d as p}from"./app.f16ebbce.js";const r={},i=n("h1",{id:"type-conversions",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#type-conversions","aria-hidden":"true"},"#"),t(" Type Conversions")],-1),u=t("Exchanging values between Java and Lua, we allow users to control how values are converted back and forth. You might want to read "),g=t("#Extra Lua Types"),k=t(" first."),y=p(`<h2 id="java-to-lua" tabindex="-1"><a class="header-anchor" href="#java-to-lua" aria-hidden="true">#</a> Java to Lua</h2><p>When pushing a Java value onto the Lua stack, you can choose from doing a <code>FULL</code> conversion, a <code>SEMI</code> conversion or <code>NONE</code> of the conversions by supplying a second parameter of type <code>Lua.Conversion</code>.</p><table><thead><tr><th style="text-align:left;">Java Types</th><th style="text-align:center;"><a href="#lua-conversion-none"><code>NONE</code></a></th><th style="text-align:center;"><a href="#lua-conversion-semi"><code>SEMI</code></a></th><th style="text-align:center;"><a href="#lua-conversion-full"><code>FULL</code></a></th><th>Conversion (if ever)</th></tr></thead><tbody><tr><td style="text-align:left;"><code>null</code></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td>Lua <code>nil</code></td></tr><tr><td style="text-align:left;"><code>Boolean</code></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td>Lua booleans</td></tr><tr><td style="text-align:left;"><code>Character</code></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td><code>lua_Integer</code> or <code>lua_Number</code></td></tr><tr><td style="text-align:left;">Boxed numerics (<code>Integer</code>...)</td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td><code>lua_Integer</code> or <code>lua_Number</code></td></tr><tr><td style="text-align:left;"><code>String</code></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td>Lua strings</td></tr><tr><td style="text-align:left;"><code>JFunction</code></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td style="text-align:center;">\u2705</td><td>A Lua closure</td></tr><tr><td style="text-align:left;">Java arrays</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td>Lua tables (index starting from 1)</td></tr><tr><td style="text-align:left;"><code>Collections&lt;?&gt;</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td>Lua tables (index starting from 1)</td></tr><tr><td style="text-align:left;"><code>Map&lt;?, ?&gt;</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td>Lua tables</td></tr><tr><td style="text-align:left;"><code>Class&lt;?&gt;</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">\u2705</td><td><code>jclass</code></td></tr><tr><td style="text-align:left;">Others</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td>Proxied to the Java side</td></tr><tr><td style="text-align:left;">Example: <code>BigInteger</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td>Proxied to the Java side</td></tr><tr><td style="text-align:left;">Example: <code>AtomicInteger</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td>Proxied to the Java side</td></tr></tbody></table><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>For a <code>SEMI</code>-conversion, roughly speaking, <strong>immutable</strong> types are converted, while mutable types, as well as those types not having Lua counterparts, are not.</p><p>For a <code>FULL</code>-conversion, all values are <strong>recursively</strong> converted if possible. Note that we ignore entries in <code>Map&lt;?&gt;</code> with a <code>null</code> key or a <code>null</code> value.</p><p>When calling Java methods from Lua, we <code>SEMI</code>-convert the return value. Currently there is no way to specify how you want the return value converted.</p></div><div class="custom-container warning"><p class="custom-container-title">Examples</p><ul><li><p><strong><code>NONE</code></strong>:</p><p>You cannot add <code>jobject</code> types up, even if their underlying class is <code>Integer</code>.</p><div class="language-java ext-java"><pre class="language-java"><code><span class="token class-name">Lua</span> <span class="token class-name">L</span> <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Lua51</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token class-name">Lua<span class="token punctuation">.</span>Conversion</span><span class="token punctuation">.</span>NONE<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">setGlobal</span><span class="token punctuation">(</span><span class="token string">&quot;i&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">assert</span> OK <span class="token operator">==</span> <span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token string">&quot;print(i:hashCode())&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">assert</span> OK <span class="token operator">!=</span> <span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token string">&quot;print(i + 1)&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">assert</span> OK <span class="token operator">==</span> <span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token string">&quot;print(java.luaify(i) + 1)&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="highlight-lines"><br><br><br><br><div class="highlight-line">\xA0</div><br></div></div></li><li><p><strong><code>FULL</code></strong>:</p><p>Changes in converted Lua objects are not propagated back to the original Java object.</p><div class="language-java ext-java"><pre class="language-java"><code><span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> array <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token keyword">int</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token punctuation">{</span> <span class="token number">100</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span>array<span class="token punctuation">,</span> <span class="token class-name">Lua<span class="token punctuation">.</span>Conversion</span><span class="token punctuation">.</span>FULL<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">setGlobal</span><span class="token punctuation">(</span><span class="token string">&quot;array&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">assert</span> <span class="token class-name">L</span><span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token string">&quot;array[1] = 1024&quot;</span><span class="token punctuation">)</span> <span class="token operator">==</span> OK<span class="token punctuation">;</span>
<span class="token keyword">assert</span> <span class="token number">100</span> <span class="token operator">==</span> array<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
</code></pre><div class="highlight-lines"><br><br><br><div class="highlight-line">\xA0</div><div class="highlight-line">\xA0</div></div></div></li></ul></div><h2 id="lua-to-java" tabindex="-1"><a class="header-anchor" href="#lua-to-java" aria-hidden="true">#</a> Lua to Java</h2><ol><li><em><strong>nil</strong></em> is converted to <code>null</code>.</li><li><em><strong>boolean</strong></em> converted to <code>boolean</code> or the boxed <code>Boolean</code>.</li><li><em><strong>integer</strong></em> / <em><strong>number</strong></em> to any of <code>char</code> <code>byte</code> <code>short</code> <code>int</code> <code>long</code> <code>float</code> <code>double</code> or their boxed alternative.</li><li><em><strong>string</strong></em> to <code>String</code>.</li><li><em><strong>table</strong></em> to <code>Map&lt;Object, Object&gt;</code>, converted recursively.</li><li><em><strong>jclass</strong></em> to <code>Class&lt;?&gt;</code>.</li><li><em><strong>jobject</strong></em> to the underlying Java object.</li><li>Other types are not converted and are <code>null</code> on the Java side.</li></ol><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>Currently, you cannot convert a C closure back to a <code>JFunction</code>, even if the closure simply wraps around <code>JFunction</code>.</p></div>`,8);function h(v,x){const e=s("RouterLink");return o(),c("div",null,[i,n("p",null,[u,l(e,{to:"/api.html#extra-lua-types"},{default:d(()=>[g]),_:1}),k]),y])}var f=a(r,[["render",h],["__file","conversions.html.vue"]]);export{f as default};
